export type Tier = "Free" | "Freemium" | "Paid"

export interface ResourceItem {
  id: string
  title: string
  description: string
  tier: Tier
  href: string
  tags: string[]
}

export interface ResourceCategory {
  slug: string
  name: string
  description: string
  icon: string        // lucide icon name for dynamic rendering
  accent: string      // tailwind text colour class
  resources: ResourceItem[]
}

// ─── Helpers ────────────────────────────────────────────────────────────────
function r(
  id: string, title: string, description: string,
  tier: Tier, href: string, tags: string[]
): ResourceItem { return { id, title, description, tier, href, tags } }

