// Derived helpers
export const RESOURCE_CATEGORY_SLUGS = RESOURCE_CATEGORIES.map((c) => c.slug)

export function getCategoryBySlug(slug: string): ResourceCategory | undefined {
  return RESOURCE_CATEGORIES.find((c) => c.slug === slug)
}

export const totalResourceCount = RESOURCE_CATEGORIES.reduce(
  (sum, c) => sum + c.resources.length, 0
)
